void sift_down(int *heap, int size, int i) {
    while (2*i+1 < size) {
        int smallest = i;
        int l = 2*i+1, r = 2*i+2;
        if (l < size && heap[l] < heap[smallest]) smallest = l;
        if (r < size && heap[r] < heap[smallest]) smallest = r;
        if (smallest == i) break;
        int temp = heap[i];
        heap[i] = heap[smallest];
        heap[smallest] = temp;
        i = smallest;
    }
}

int extract_min(int *heap, int *size) {
    int min_val = heap[0];
    heap[0] = heap[--(*size)];
    sift_down(heap, *size, 0);
    return min_val;
}

