    while (i > 0 && heap[i] < heap[(i-1)/2]) {
        int p = (i - 1) / 2;
        int t = heap[i]; heap[i] = heap[p]; heap[p] = t;
        i = p;
    }
}

void sift_down(int *heap, int size, int i) {
    while (2*i+1 < size) {
        int sm = i, l = 2*i+1, r = 2*i+2;
        if (l < size && heap[l] < heap[sm]) sm = l;
        if (r < size && heap[r] < heap[sm]) sm = r;
        if (sm == i) break;
        int t = heap[i]; heap[i] = heap[sm]; heap[sm] = t;
        i = sm;
    }
}

void insert(int *heap, int *sz, int val) {
    heap[*sz] = val;
    sift_up(heap, *sz);
    (*sz)++;
}

int extract_min(int *heap, int *sz) {
    int min_val = heap[0];
    heap[0] = heap[--(*sz)];
    sift_down(heap, *sz, 0);
    return min_val;
}

int main() {
    int heap[100];
    int sz = 0;
    int vals[] = {3, 1, 4, 1, 5};
    for (int i = 0; i < 5; i++)
        insert(heap, &sz, vals[i]);

    printf("%d\n", extract_min(heap, &sz));
